      const _pool = Object.assign({}, (afterResult_create_auto?.output ?? {}));
      const _fixtureInput = { cv: "cv-auto-1", step_ref: "step-1", check_ref: "check-1", mode: "automated" } as Record<string, unknown>;
      for (const [k, v] of Object.entries(_pool)) {
        if (k in _fixtureInput && v !== undefined) {
          const cur = _fixtureInput[k];
          const isPlaceholder = cur === null || cur === undefined || (typeof cur === 'string' && cur.startsWith('test-'));
          if (isPlaceholder) _fixtureInput[k] = v;
        }
      }
      const result = await interpret(checkVerificationHandler.create({ ..._fixtureInput }), storage);
