  describe('register()', () => {
    it('declares concept name', async () => {
      if (typeof checkVerificationHandler.register !== 'function') return;
      const storage = createInMemoryStorage();
      const program = checkVerificationHandler.register({});
      // If it's a StorageProgram, interpret it
      const result = (program?.instructions && !program.variant)
        ? await interpret(program, storage)
        : program;
      if (!result?.variant) return; // handler does not support register introspection
      expect(result.variant).toBe('ok');
      const name = result.output?.name ?? result.name;
      expect(name).toBe('CheckVerification');
    });
  });

  describe('invariant examples', () => {
    it("create then get", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(checkVerificationHandler.create({ cv: "cv-ex-1", step_ref: "step-10", check_ref: "check-10", mode: "automated" }), storage);
      expect(createResult0.variant).toBe("ok");
      let cv = createResult0.output["cv"];
      const thenResult0 = await interpret(checkVerificationHandler.get({ cv: "cv-ex-1" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("evaluate sets passing", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(checkVerificationHandler.create({ cv: "cv-ex-2", step_ref: "step-11", check_ref: "check-11", mode: "automated" }), storage);
      expect(createResult0.variant).toBe("ok");
      let cv = createResult0.output["cv"];
      const thenResult0 = await interpret(checkVerificationHandler.evaluate({ cv: "cv-ex-2" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("waive clears score", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(checkVerificationHandler.create({ cv: "cv-ex-3", step_ref: "step-12", check_ref: "check-12", mode: "human" }), storage);
      expect(createResult0.variant).toBe("ok");
      let cv = createResult0.output["cv"];
      const thenResult0 = await interpret(checkVerificationHandler.waive({ cv: "cv-ex-3", justification: "Not applicable" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: waived checks have no score', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('evaluate'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('judge'), input: fc.record({ cv: fc.string(), verdict: fc.string({ minLength: 1, maxLength: 50 }), evidence: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('waive'), input: fc.record({ cv: fc.string(), justification: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('rollup'), input: fc.record({ cv: fc.string(), child_verifications: fc.string() }) }),
              fc.record({ action: fc.constant('reset'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('create'), input: fc.record({ cv: fc.string(), step_ref: fc.string({ minLength: 1, maxLength: 50 }), check_ref: fc.string({ minLength: 1, maxLength: 50 }), mode: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = checkVerificationHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(checkVerificationHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphan verification', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('evaluate'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('judge'), input: fc.record({ cv: fc.string(), verdict: fc.string({ minLength: 1, maxLength: 50 }), evidence: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('waive'), input: fc.record({ cv: fc.string(), justification: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('rollup'), input: fc.record({ cv: fc.string(), child_verifications: fc.string() }) }),
              fc.record({ action: fc.constant('reset'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ cv: fc.string() }) }),
              fc.record({ action: fc.constant('create'), input: fc.record({ cv: fc.string(), step_ref: fc.string({ minLength: 1, maxLength: 50 }), check_ref: fc.string({ minLength: 1, maxLength: 50 }), mode: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = checkVerificationHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(checkVerificationHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: orphan verification
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

